    #[must_use]
    pub fn clamp_date(&self, date: CalendarDate) -> CalendarDate {
        let mut clamped = date;

        if let Some(min) = &self.min
            && clamped.compare(min) == Ordering::Less
        {
            clamped = min.clone();
        }

        if let Some(max) = &self.max
            && clamped.compare(max) == Ordering::Greater
        {
