    #[must_use]
    pub fn heading_text(&self) -> String {
        format!(
            "{} {}",
            self.ctx
                .intl_backend
                .month_long_name(self.ctx.visible_month, &self.ctx.locale),
            self.ctx.visible_year,
        )
    }

    /// Attributes for the grid wrapper of the first visible month.
    #[must_use]
    pub fn grid_attrs(&self) -> AttrMap {
