#[test]
fn first_click_sets_anchor_and_second_click_completes_range() {
    let mut svc = service();

    drop(svc.send(Event::SelectDate {
        date: date(2024, 1, 10),
    }));

    assert_eq!(svc.context().anchor_date, Some(date(2024, 1, 10)));
    assert_eq!(*svc.context().value.get(), None);

    drop(svc.send(Event::SelectDate {
        date: date(2024, 1, 15),
